cd /workspace/data
python3 - <<'EOF'
import collections
rows=[l.split('\t') for l in open('izh.trn').read().splitlines() if l.strip()]
by_lemma=collections.defaultdict(dict)
for lem,surf,feat in rows:
    by_lemma[lem][feat]=surf
# singular stem from GEN;SG (minus n), plural stem from GEN;PL (minus n)
def get(d,f): return d.get(f)
missing=0
end=collections.defaultdict(collections.Counter)
for lem,d in by_lemma.items():
    gsg=get(d,'N;GEN;SG') or get(d,'ADJ;GEN;SG')
    gpl=get(d,'N;GEN;PL') or get(d,'ADJ;GEN;PL')
    ssg=gsg[:-1] if gsg else None
    spl=gpl[:-1] if gpl else None
    for feat,surf in d.items():
        pos,case,num=feat.split(';')
        stem=ssg if num=='SG' else spl
        if stem and surf.startswith(stem):
            end[(case,num)][surf[len(stem):]]+=1
        else:
            end[(case,num)]['<NOSTEM:%s>'%surf]+=1
for k in sorted(end):
    print(k, dict(end[k]))
EOF

