V='aeiouäöüy'
def is_long(s): return len(s)>=2 and s[-1] in V and s[-2]==s[-1]
def is_diph_i(s): return s.endswith('i') and len(s)>=2 and s[-2] in V and s[-2]!='i'
def lengthen(s):
    if not s or s[-1] not in V: return s
    if is_long(s) or is_diph_i(s): return s
    return s+s[-1]
def collapse_i(s):
    return s[:-1] if s.endswith('ii') else s
def harmony(s): return 'ä' if any(c in 'äöüy' for c in s) else 'a'
def strp(v,suf):
    if v is None: return None
    return v[:-len(suf)] if (suf=='' or v.endswith(suf)) else None
def vote(d,cands,post=lambda x:x):
    c=collections.Counter()
    for k,suf in cands:
        r=strp(d.get(k),suf)
        if r is not None: c[post(r)]+=1
    return c.most_common(1)[0][0] if c else None
def weak_sg(d): return vote(d,[(('GEN','SG'),'n'),(('IN+ABL','SG'),'st'),(('TRANS','SG'),'ks'),(('AT+ABL','SG'),'lt'),(('AT+ALL','SG'),'lle')])
def weak_pl(d): return vote(d,[(('IN+ABL','PL'),'st'),(('TRANS','PL'),'ks'),(('AT+ABL','PL'),'lt'),(('AT+ALL','PL'),'lle')])
def strong_pl(d):
    v=vote(d,[(('GEN','PL'),'n'),(('ESS','PL'),'n')],collapse_i)
    return v if v else vote(d,[(('IN+ALL','PL'),'he')])
def strong_sg(d,lem):
    if lem[-1] in V: return lem
    return weak_sg(d) or lem
def sg_lengthens(d,ws):
    for key,suf in [(('AT+ESS','SG'),'l'),(('IN+ESS','SG'),'z')]:
        v=d.get(key)
        if v is None or ws is None: continue
        if v==ws+suf: return False
        if v==lengthen(ws)+suf: return True
    return True

